print(max(1, 2, 3))
print(min([5, 2, 8, 1]))
print(sum(range(11)))
print(list(range(5)))
print(list(reversed([1, 2, 3])))
print(sorted([3, 1, 2]))
print(list(enumerate(["a", "b", "c"])))
print(list(zip([1, 2], ["x", "y"])))
print(list(map(lambda x: x * 2, [1, 2, 3])))
print(list(filter(lambda x: x > 2, [1, 2, 3, 4])))
print(any([False, False, True]))
print(all([True, True, True]))
print(ord("A"))
print(chr(65))
print(hex(255))
print(oct(8))
print(bin(5))
print(int("42"))
print(float("3.5"))
print(str(123))
